import React, { useEffect, useState, useCallback } from "react";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from "recharts";
import Navbar from "../components/Navbar";
import axiosClient from "../api/axiosClient";
import { useAuth } from "../context/AuthContext";

const TABS = ["Overview", "Households", "Meter Uploads", "Tariff Plans", "Billing Cycles", "Alerts"];

export default function AdminPanel() {
  const { user } = useAuth();
  const [apartmentId, setApartmentId] = useState(user?.apartmentId || "");
  const [apartments, setApartments] = useState([]);
  const [tab, setTab] = useState("Overview");

  useEffect(() => {
    axiosClient.get("/public/apartments").then((res) => setApartments(res.data)).catch(() => {});
  }, []);

  return (
    <div style={{ background: "#f1f5f9", minHeight: "100vh", paddingBottom: "60px", fontFamily: "system-ui, sans-serif" }}>
      <Navbar />
      <div className="container" style={{ maxWidth: "1200px", margin: "0 auto", padding: "40px 24px 0 24px" }}>

        {/* CONSOLE HEADER */}
        <div style={{ background: "linear-gradient(135deg, #0f172a 0%, #1e293b 100%)", padding: "32px", borderRadius: "20px", color: "#fff", marginBottom: "32px", boxShadow: "0 10px 25px -5px rgba(15,23,42,0.1)" }}>
          <h1 style={{ fontSize: "28px", fontWeight: "700", letterSpacing: "-0.01em" }}>Admin Console</h1>
          <p style={{ color: "#94a3b8", fontSize: "14px", marginTop: "4px" }}>System architecture configuration context: Manage structural parameters, billing, logs, and triggers.</p>
        </div>

        {/* SELECT CONTROL */}
        <div style={{ background: "#fff", padding: "20px", borderRadius: "16px", border: "1px solid #e2e8f0", display: "flex", alignItems: "center", gap: "16px", marginBottom: "24px" }}>
          <div>
            <label style={{ display: "block", fontSize: "11px", textTransform: "uppercase", fontWeight: "700", color: "#64748b", marginBottom: "4px" }}>Active Managing Context</label>
            <select style={{ background: "#f8fafc", border: "1px solid #cbd5e1", padding: "10px 16px", borderRadius: "8px", fontWeight: "600", color: "#0f172a", minWidth: "260px" }} value={apartmentId} onChange={(e) => setApartmentId(e.target.value)}>
              <option value="">Choose apartment complex...</option>
              {apartments.map((a) => <option key={a.id} value={a.id}>{a.name}</option>)}
            </select>
          </div>
        </div>

        {/* TAB CONTROLLER */}
        <div style={{ display: "flex", gap: "8px", background: "#e2e8f0", padding: "6px", borderRadius: "12px", marginBottom: "32px", overflowX: "auto" }}>
          {TABS.map((t) => (
            <button key={t} onClick={() => setTab(t)} style={{
              flex: 1, padding: "10px 16px", borderRadius: "8px", border: "none", fontWeight: "600", fontSize: "14px",
              cursor: "pointer", background: tab === t ? "#ffffff" : "transparent", color: tab === t ? "#0f172a" : "#475569",
              boxShadow: tab === t ? "0 4px 10px rgba(0,0,0,0.05)" : "none", whiteSpace: "nowrap"
            }}>{t}</button>
          ))}
        </div>

        {/* CONDITIONAL ARCHITECTURE VIEWS */}
        {!apartmentId ? (
          <div style={{ background: "#fff", borderRadius: "20px", padding: "48px", textAlign: "center", border: "1px solid #e2e8f0" }}>
            <div style={{ fontSize: "40px", marginBottom: "16px" }}>🏢</div>
            <h3 style={{ color: "#0f172a", fontSize: "18px", fontWeight: "700" }}>No Workspace Selected</h3>
            <p style={{ color: "#64748b", fontSize: "14px", marginTop: "4px" }}>Select an active tracking apartment context model above or define a new framework entity below.</p>
          </div>
        ) : (
          <div style={{ minHeight: "400px" }}>
            {tab === "Overview" && <OverviewTab apartmentId={apartmentId} />}
            {tab === "Households" && <HouseholdsTab apartmentId={apartmentId} />}
            {tab === "Meter Uploads" && <MeterUploadTab apartmentId={apartmentId} />}
            {tab === "Tariff Plans" && <TariffTab apartmentId={apartmentId} />}
            {tab === "Billing Cycles" && <BillingTab apartmentId={apartmentId} />}
            {tab === "Alerts" && <AlertsTab apartmentId={apartmentId} />}
          </div>
        )}

        {!apartmentId && <CreateApartmentCard onCreated={(a) => setApartments((prev) => [...prev, a])} />}
      </div>
    </div>
  );
}

// SHARED INTERFACE CARD STYLING MAP
const cardStyle = { background: "#ffffff", padding: "24px", borderRadius: "16px", border: "1px solid #e2e8f0", boxShadow: "0 4px 6px -1px rgba(0,0,0,0.02)" };
const inputStyle = { width: "100%", padding: "10px 14px", borderRadius: "8px", border: "1px solid #cbd5e1", marginTop: "4px", background: "#f8fafc" };
const buttonPrimary = { background: "#0f172a", color: "#fff", padding: "12px 24px", border: "none", borderRadius: "8px", fontWeight: "600", cursor: "pointer" };

function CreateApartmentCard({ onCreated }) {
  const [name, setName] = useState("");
  const [address, setAddress] = useState("");
  const [message, setMessage] = useState("");

  const submit = async (e) => {
    e.preventDefault();
    const res = await axiosClient.post("/admin/apartments", { name, address });
    onCreated(res.data);
    setMessage(`Apartment "${res.data.name}" mapped.`);
    setName(""); setAddress("");
  };

  return (
    <div style={{ ...cardStyle, marginTop: "40px", maxWidth: "500px" }}>
      <h3 style={{ fontSize: "18px", fontWeight: "700", marginBottom: "16px", color: "#0f172a" }}>Map New Apartment Architecture</h3>
