      <form onSubmit={submit} style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
        <div><label style={{ fontSize: "13px", color: "#475569" }}>Apartment Identifier Name</label><input style={inputStyle} value={name} onChange={(e) => setName(e.target.value)} required /></div>
        <div><label style={{ fontSize: "13px", color: "#475569" }}>Geographical Base Address</label><input style={inputStyle} value={address} onChange={(e) => setAddress(e.target.value)} required /></div>
