    </div>
  );
}

function OverviewTab({ apartmentId }) {
  const [households, setHouseholds] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [comparison, setComparison] = useState([]);

  useEffect(() => {
    axiosClient.get(`/admin/apartments/${apartmentId}/households`).then((r) => setHouseholds(r.data)).catch(() => {});
    axiosClient.get(`/admin/apartments/${apartmentId}/alerts`).then((r) => setAlerts(r.data)).catch(() => {});
    axiosClient.get(`/admin/apartments/${apartmentId}/usage-comparison`).then((r) => setComparison(r.data)).catch(() => {});
  }, [apartmentId]);

  const avgUsage = comparison.length
    ? (comparison.reduce((s, c) => s + Number(c.totalConsumptionKl || 0), 0) / comparison.length).toFixed(2)
    : "0.00";

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "24px" }}>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: "24px" }}>
        {[
          { label: "Mapped Households", val: households.length, color: "#2563eb" },
          { label: "Active Operational Alerts", val: alerts.length, color: "#dc2626" },
          { label: "Avg Node Delivery Consumption", val: `${avgUsage} kL`, color: "#0d9488" },
          { label: "Meters Signaling Online", val: comparison.length, color: "#4f46e5" }
        ].map((s, idx) => (
          <div key={idx} style={{ ...cardStyle, borderLeft: `4px solid ${s.color}` }}>
            <div style={{ fontSize: "13px", color: "#64748b", fontWeight: "600" }}>{s.label}</div>
            <div style={{ fontSize: "28px", fontWeight: "700", color: "#0f172a", marginTop: "4px" }}>{s.val}</div>
          </div>
        ))}
      </div>

      <div style={cardStyle}>
        <h3 style={{ fontSize: "16px", fontWeight: "700", marginBottom: "20px" }}>Consumption Analysis Framework Matrix</h3>
        <ResponsiveContainer width="100%" height={280}>
          <BarChart data={comparison}>
            <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
            <XAxis dataKey="flatNumber" fontSize={11} stroke="#94a3b8" />
            <YAxis fontSize={11} stroke="#94a3b8" />
            <Tooltip cursor={{ fill: "rgba(0,0,0,0.02)" }} />
            <Bar dataKey="totalConsumptionKl" fill="#0284c7" radius={[4, 4, 0, 0]} />
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

