function MeterUploadTab({ apartmentId }) {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");

  const submit = async (e) => {
    e.preventDefault();
    setError(""); setResult(null);
    if (!file) return;
    const formData = new FormData();
    formData.append("apartmentId", apartmentId);
    formData.append("file", file);
    try {
      const res = await axiosClient.post("/admin/usage-logs/bulk-upload", formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      setResult(res.data);
    } catch (err) { setError(err.response?.data?.message || "Upload failed."); }
  };

  return (
    <div style={{ ...cardStyle, maxWidth: "600px" }}>
      <h3 style={{ fontSize: "16px", fontWeight: "700", marginBottom: "8px" }}>Bulk Ingestion Subsystem (CSV)</h3>
      <p style={{ fontSize: "13px", color: "#64748b", marginBottom: "20px" }}>Columns target structure formatting: <code>flat_number, reading_date (YYYY-MM-DD), reading_value</code>.</p>
      {error && <div style={{ background: "#fee2e2", color: "#b91c1c", padding: "12px", borderRadius: "8px", fontSize: "13px", marginBottom: "16px" }}>{error}</div>}
      <form onSubmit={submit}>
        <div style={{ border: "2px dashed #cbd5e1", padding: "32px", borderRadius: "12px", textAlign: "center", background: "#f8fafc", marginBottom: "16px" }}>
          <input type="file" accept=".csv" onChange={(e) => setFile(e.target.files[0])} required style={{ cursor: "pointer" }} />
        </div>
        <button style={buttonPrimary}>Execute Array Ingestion</button>
      </form>
      {result && <div style={{ background: "#f0fdf4", color: "#16a34a", padding: "16px", borderRadius: "8px", marginTop: "16px", fontSize: "13px" }}>Processed {result.totalRows} matrix values. Commits verified.</div>}
    </div>
  );
}

