function BillingTab({ apartmentId }) {
  const [cycles, setCycles] = useState([]);
  const [openForm, setOpenForm] = useState({ startDate: "", endDate: "" });
  const [purchaseForm, setPurchaseForm] = useState({ billingCycleId: "", purchasedVolumeKl: "", unitCost: "" });
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const load = useCallback(() => {
    axiosClient.get(`/admin/apartments/${apartmentId}/billing-cycles`).then((r) => setCycles(r.data)).catch(() => {});
  }, [apartmentId]);

  useEffect(() => { load(); }, [load]);

  const openCycle = async (e) => {
    e.preventDefault(); setError(""); setMessage("");
    try {
      await axiosClient.post("/admin/billing-cycles", { apartmentId, ...openForm });
      setMessage("Billing tracking framework initialized.");
      setOpenForm({ startDate: "", endDate: "" });
      load();
    } catch (err) { setError(err.response?.data?.message || "Fault state initialization."); }
  };

  const recordPurchase = async (e) => {
    e.preventDefault(); setError(""); setMessage("");
    try {
      await axiosClient.post("/admin/billing-cycles/purchases", {
        billingCycleId: purchaseForm.billingCycleId,
        purchasedVolumeKl: Number(purchaseForm.purchasedVolumeKl),
        unitCost: Number(purchaseForm.unitCost),
      });
      setMessage("External structural procurement transaction integrated.");
      setPurchaseForm({ billingCycleId: "", purchasedVolumeKl: "", unitCost: "" });
      load();
    } catch (err) { setError(err.response?.data?.message || "Procurement log failure."); }
  };

  const finalize = async (id) => {
    setError(""); setMessage("");
    try {
      await axiosClient.post(`/admin/billing-cycles/${id}/finalize`);
      setMessage("Invoices generated. Asynchronous delivery execution completed.");
      load();
    } catch (err) { setError(err.response?.data?.message || "Execution exception error."); }
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "24px" }}>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "24px" }}>
        <div style={cardStyle}>
          <h3 style={{ fontSize: "16px", fontWeight: "700", marginBottom: "16px" }}>Initialize Cycle Window</h3>
          <form onSubmit={openCycle} style={{ display: "flex", flexDirection: "column", gap: "12px" }}>
            <div><label style={{ fontSize: "12px" }}>Start Date</label><input type="date" style={inputStyle} value={openForm.startDate} onChange={(e) => setOpenForm({ ...openForm, startDate: e.target.value })} required /></div>
            <div><label style={{ fontSize: "12px" }}>End Date</label><input type="date" style={inputStyle} value={openForm.endDate} onChange={(e) => setOpenForm({ ...openForm, endDate: e.target.value })} required /></div>
            <button style={{ ...buttonPrimary, marginTop: "8px" }}>Open Window</button>
          </form>
        </div>

        <div style={cardStyle}>
          <h3 style={{ fontSize: "16px", fontWeight: "700", marginBottom: "16px" }}>Log Bulk Volume Acquisition</h3>
          <form onSubmit={recordPurchase} style={{ display: "flex", flexDirection: "column", gap: "12px" }}>
            <div>
              <label style={{ fontSize: "12px" }}>Target Frame Window</label>
              <select style={inputStyle} value={purchaseForm.billingCycleId} onChange={(e) => setPurchaseForm({ ...purchaseForm, billingCycleId: e.target.value })} required>
                <option value="">Choose open pipeline...</option>
                {cycles.filter(c => c.status === "OPEN").map((c) => (<option key={c.id} value={c.id}>{c.startDate} to {c.endDate}</option>))}
              </select>
            </div>
            <div><label style={{ fontSize: "12px" }}>Procured Quantity (kL)</label><input type="number" step="0.01" style={inputStyle} value={purchaseForm.purchasedVolumeKl} onChange={(e) => setPurchaseForm({ ...purchaseForm, purchasedVolumeKl: e.target.value })} required /></div>
            <div><label style={{ fontSize: "12px" }}>Unit Cost Coefficient</label><input type="number" step="0.01" style={inputStyle} value={purchaseForm.unitCost} onChange={(e) => setPurchaseForm({ ...purchaseForm, unitCost: e.target.value })} required /></div>
            <button style={{ ...buttonPrimary, marginTop: "8px" }}>Log Procurement</button>
          </form>
        </div>
      </div>

      <div style={cardStyle}>
        <h3 style={{ fontSize: "16px", fontWeight: "700", marginBottom: "16px" }}>Active Cycles Framework Array</h3>
        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "14px" }}>
          <thead>
            <tr style={{ borderBottom: "2px solid #e2e8f0", fontSize: "11px", color: "#64748b", textTransform: "uppercase", textAlign: "left" }}>
              <th style={{ padding: "12px" }}>Period Frame</th><th style={{ padding: "12px" }}>Status Flag</th><th style={{ padding: "12px" }}>Volume</th><th style={{ padding: "12px" }}>Base Cost</th><th style={{ padding: "12px" }}>Pipeline Actions</th>
            </tr>
          </thead>
          <tbody>
            {cycles.map((c) => (
              <tr key={c.id} style={{ borderBottom: "1px solid #f1f5f9" }}>
                <td style={{ padding: "12px", fontWeight: "600" }}>{c.startDate} → {c.endDate}</td>
                <td style={{ padding: "12px" }}><span style={{ padding: "2px 8px", borderRadius: "999px", fontSize: "12px", background: c.status === "OPEN" ? "#e0f2fe" : "#dcfce7", color: c.status === "OPEN" ? "#0369a1" : "#15803d" }}>{c.status}</span></td>
                <td style={{ padding: "12px" }}>{c.totalPurchasedVolumeKl} kL</td><td style={{ padding: "12px" }}>Rs. {c.unitCost}</td>
                <td style={{ padding: "12px" }}>{c.status === "OPEN" && <button style={{ background: "#0284c7", color: "#fff", border: "none", padding: "6px 12px", borderRadius: "6px", cursor: "pointer", fontWeight: "600" }} onClick={() => finalize(c.id)}>Execute Finalization Matrix</button>}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

